def get_user_by_id(user_id):
    """Retrieve a single user by ID."""
    users = get_mock_users()
    for user in users:
        if user["id"] == str(user_id):
            return user
    return None


def get_all_users(page=1, limit=10, search=""):
    """Retrieve all users with pagination and optional search filtering."""
    users = get_mock_users()
    
    # Apply search filter
    if search:
        search_lower = search.lower()
        users = [
            user for user in users
            if search_lower in user["name"].lower()
            or search_lower in user["email"].lower()
            or search_lower in user["department"].lower()
            or search_lower in user["role"].lower()
        ]
    
    # Apply pagination
    start_index = (page - 1) * limit
    end_index = start_index + limit
    
    return users[start_index:end_index]


def create_user(user_data):
    """Create a new user (mock implementation)."""
    required_fields = ["name", "email"]
    if not all(field in user_data for field in required_fields):
        return None
    
    import uuid
    new_user = {
        "id": str(uuid.uuid4())[:8],
        "name": user_data["name"],
        "email": user_data["email"],
        "role": user_data.get("role", "developer"),
        "department": user_data.get("department", "Unassigned"),
        "status": "active",
        "created_at": "2024-12-01T00:00:00Z",
        "avatar_url": f"https://api.example.com/avatars/default.png"
    }
    return new_user


def update_user(user_id, update_data):
    """Update an existing user (mock implementation)."""
    user = get_user_by_id(user_id)
    if not user:
        return None
    
    updatable_fields = ["name", "email", "role", "department", "status"]
    for field in updatable_fields:
        if field in update_data:
            user[field] = update_data[field]
    
    return user


def delete_user(user_id):
    """Delete a user (mock implementation)."""
    user = get_user_by_id(user_id)
    return user is not None


